import os
import json
import yaml
from pathlib import Path
from typing import Dict, Any, Union
from dataclasses import dataclass, field

@dataclass
class ${1:AppConfig}:
    """${2:Application configuration}."""

    # Database settings
    database_url: str = field(default="sqlite:///app.db")
    database_echo: bool = field(default=False)

    # Server settings
    host: str = field(default="0.0.0.0")
    port: int = field(default=8000)
    debug: bool = field(default=False)

    # Logging
    log_level: str = field(default="INFO")
    log_file: str = field(default=None)

    # API settings
    api_key: str = field(default="")
    rate_limit: int = field(default=100)

    @classmethod
    def from_file(cls, config_path: Union[str, Path]) -> '${1:AppConfig}':
        """Load configuration from file."""
        config_path = Path(config_path)

        if not config_path.exists():
            raise FileNotFoundError(f"Config file not found: {config_path}")

        if config_path.suffix.lower() == '.json':
            with open(config_path) as f:
                data = json.load(f)
        elif config_path.suffix.lower() in ['.yml', '.yaml']:
            with open(config_path) as f:
                data = yaml.safe_load(f)
        else:
            raise ValueError(f"Unsupported config format: {config_path.suffix}")

        return cls(**data)

    @classmethod
    def from_env(cls, prefix: str = "APP_") -> '${1:AppConfig}':
        """Load configuration from environment variables."""
        config = cls()

        for field_name in config.__dataclass_fields__:
            env_name = f"{prefix}{field_name.upper()}"
            env_value = os.getenv(env_name)

            if env_value is not None:
                field_type = config.__dataclass_fields__[field_name].type

                if field_type == bool:
                    value = env_value.lower() in ('true', '1', 'yes', 'on')
                elif field_type == int:
                    value = int(env_value)
                else:
                    value = env_value

                setattr(config, field_name, value)

        return config

    def to_dict(self) -> Dict[str, Any]:
        """Convert config to dictionary."""
        return {
            field.name: getattr(self, field.name)
            for field in self.__dataclass_fields__.values()
        }

    def save_to_file(self, config_path: Union[str, Path]):
        """Save configuration to file."""
        config_path = Path(config_path)
        config_path.parent.mkdir(parents=True, exist_ok=True)

        data = self.to_dict()

        if config_path.suffix.lower() == '.json':
            with open(config_path, 'w') as f:
                json.dump(data, f, indent=2)
        elif config_path.suffix.lower() in ['.yml', '.yaml']:
            with open(config_path, 'w') as f:
                yaml.dump(data, f, default_flow_style=False)
        else:
            raise ValueError(f"Unsupported config format: {config_path.suffix}")

